import { LiveClient } from "@/components/LiveClient";
import { getYouTubeVideos } from "@/lib/youtube";

export default async function LivePage() {
  const videos = await getYouTubeVideos();

  const live = videos.find((v) => v.liveBroadcastContent === "live");
  const featured = live || videos[0];

  return (
    <main className="min-h-screen bg-black text-white p-4">
      <div className="max-w-7xl mx-auto space-y-6">

        {/* HAUT : PLAYER + CHAT */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">

          {/* PLAYER */}
          <div className="lg:col-span-2">
            {featured && (
              <>
                <div className="aspect-video bg-black rounded overflow-hidden">
                  <iframe
                    className="w-full h-full"
                    src={`https://www.youtube.com/embed/${featured.id}`}
                    allowFullScreen
                  />
                </div>

                <h2 className="mt-2 text-lg font-semibold">
                  {featured.liveBroadcastContent === "live" ? "🔴 LIVE - " : ""}
                  {featured.title}
                </h2>
              </>
            )}
          </div>

          {/* CHAT */}
          <div className="bg-neutral-900 p-3 rounded h-[500px] overflow-hidden flex flex-col">
            <div className="mb-2 text-sm font-semibold">Chat</div>

            <div className="flex-1 overflow-y-auto">
              <LiveClient />
            </div>
          </div>

        </div>

        {/* BAS : VIDEOS */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {videos.slice(1, 7).map((v) => (
            <a
              key={v.id}
              href={`https://www.youtube.com/watch?v=${v.id}`}
              target="_blank"
              className="block"
            >
              <img src={v.thumbnail} className="w-full rounded" />
              <p className="text-sm mt-1">{v.title}</p>
            </a>
          ))}
        </div>

      </div>
    </main>
  );
}